import React, { useState, useEffect } from 'react';
import './Hero.css';

const Hero = () => {
  const [yearsCount, setYearsCount] = useState(0);
  const [typedText, setTypedText] = useState('');
  const [currentPhase, setCurrentPhase] = useState(0);

  useEffect(() => {
    const targetYears = 5;
    const duration = 2000; // 2 seconds
    const increment = targetYears / (duration / 50);

    const timer = setInterval(() => {
      setYearsCount(prev => {
        if (prev >= targetYears) {
          clearInterval(timer);
          return targetYears;
        }
        return Math.min(prev + increment, targetYears);
      });
    }, 50);

    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const phrases = ['STAY HOME', 'SHOP ONLINE'];
    const currentText = phrases[currentPhase];

    if (currentPhase < phrases.length) {
      let i = 0;
      setTypedText('');

      const typing = setInterval(() => {
        if (i < currentText.length) {
          setTypedText(prev => prev + currentText[i]);
          i++;
        } else {
          clearInterval(typing);
          // Wait 2 seconds before starting next phrase
          setTimeout(() => {
            setCurrentPhase(prev => prev + 1);
          }, 2000);
        }
      }, 100);

      return () => clearInterval(typing);
    }
  }, [currentPhase]);

  const handleAddToCart = (productName) => {
    setCartNotification({ show: true, productName });
    setTimeout(() => {
      setCartNotification({ show: false, productName: '' });
    }, 3000);
  };

  const handleViewProduct = (product) => {
    setSelectedProduct(product);
  };

  const closeProductView = () => {
    setSelectedProduct(null);
  };

  return (
    <>
      {/* Cart Notification */}
      {cartNotification.show && (
        <div className="cart-notification">
          <div className="notification-content">
            <p>✅ {cartNotification.productName} added to cart!</p>
            <button className="view-cart-btn">View Cart</button>
          </div>
        </div>
      )}

      {/* Product Detail Modal */}
      {selectedProduct && (
        <div className="product-modal-overlay" onClick={closeProductView}>
          <div className="product-modal" onClick={(e) => e.stopPropagation()}>
            <button className="close-modal" onClick={closeProductView}>×</button>
            <div className="modal-content">
              <img src={selectedProduct.image} alt={selectedProduct.name} />
              <div className="modal-info">
                <h3>{selectedProduct.name}</h3>
                <p className="modal-description">{selectedProduct.description}</p>
                <div className="modal-actions">
                  <button 
                    className="modal-add-to-cart"
                    onClick={() => handleAddToCart(selectedProduct.name)}
                  >
                    + Add to Cart
                  </button>
                  <button className="modal-favorite">❤️ Favorite</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <section className="hero">
      {/* Animated Background */}
      <div className="hero-background">
        <div className="floating-element herb-1">🌿</div>
        <div className="floating-element herb-2">🍃</div>
        <div className="floating-element herb-3">🌱</div>
        <div className="floating-element remedy-1">🌱</div>
        <div className="floating-element remedy-2">🧪</div>
        <div className="floating-element remedy-3">🌱</div>
      </div>

      {/* Three Hero Sections */}
      <div className="hero-three-sections">
        <div className="hero-card main-welcome-card animate-slide-left">
          <div className="card-image">
